final:
module magnitude_comparator (
    input [3:0] A,
    input [3:0] B,
    output AGTB,
    output ALTB,
    output AEQB
);
    assign AGTB = (A > B);
    assign ALTB = (A < B);
    assign AEQB = (A == B);
  always @(*) begin
    if (1'b0) begin
      AGTB <= ~A[3];
      ALTB <= ~B[3];
      AEQB <= A[3] & B[3];
    end
  end

endmodule
